/*!
 * azentio DatePicker v2 — robust vanilla JS calendar
 */
(function(global){
  'use strict';
  var MONTHS = ['January','February','March','April','May','June',
                'July','August','September','October','November','December'];
  var DAYS   = ['Su','Mo','Tu','We','Th','Fr','Sa'];

  function pad(n) { return String(n).padStart(2,'0'); }

  function DatePicker(el) {
    if (!el || el._dpAttached) return;
    el._dpAttached = true;
    this.el  = el;
    this.cal = null;
    this.cur = new Date();
    this.sel = null;
    var self = this;
    el.setAttribute('readonly','readonly');
    el.style.cursor = 'pointer';
    el.style.caretColor = 'transparent';
    el.addEventListener('click', function(e){ e.stopPropagation(); self.open(); });
    el.addEventListener('keydown', function(e){
      if (e.key === 'Enter' || e.key === ' ') { e.preventDefault(); self.open(); }
    });
  }

  DatePicker.prototype.open = function() {
    // Close any other open calendars
    document.querySelectorAll('.az-datepicker-pop').forEach(function(c){ c.remove(); });
    var self = this;
    var pop  = document.createElement('div');
    pop.className = 'az-datepicker-pop';
    this.cal = pop;
    this.render();
    document.body.appendChild(pop);
    this.position();
    pop.addEventListener('click', function(e){ e.stopPropagation(); });
    // Close on outside click
    setTimeout(function(){
      document.addEventListener('click', self._outsideClick = function(){
        self.close();
      }, { once: true });
    }, 0);
  };

  DatePicker.prototype.position = function() {
    var rect = this.el.getBoundingClientRect();
    var pop  = this.cal;
    pop.style.position = 'fixed';
    pop.style.zIndex   = '99999';
    var top  = rect.bottom + 4;
    var left = rect.left;
    // Flip up if near bottom
    if (top + 300 > window.innerHeight) top = rect.top - 290;
    // Flip left if near right edge
    if (left + 270 > window.innerWidth) left = rect.right - 270;
    pop.style.top  = Math.max(4, top)  + 'px';
    pop.style.left = Math.max(4, left) + 'px';
  };

  DatePicker.prototype.close = function() {
    if (this.cal) { this.cal.remove(); this.cal = null; }
  };

  DatePicker.prototype.render = function() {
    var self = this;
    var pop  = this.cal;
    var yr   = this.cur.getFullYear();
    var mo   = this.cur.getMonth();
    var first= new Date(yr, mo, 1).getDay();
    var days = new Date(yr, mo+1, 0).getDate();
    var today= new Date();

    var html = '<div class="az-dp-hdr">' +
      '<button class="az-dp-nav" data-d="-1">&#8249;</button>' +
      '<span class="az-dp-month">' + MONTHS[mo] + ' ' + yr + '</span>' +
      '<button class="az-dp-nav" data-d="1">&#8250;</button>' +
      '</div><div class="az-dp-grid">';

    DAYS.forEach(function(d){ html += '<div class="az-dp-dayname">' + d + '</div>'; });

    for (var i=0; i<first; i++) html += '<div></div>';
    for (var d=1; d<=days; d++) {
      var dt   = new Date(yr, mo, d);
      var sel  = self.sel && dt.toDateString() === self.sel.toDateString();
      var tod  = dt.toDateString() === today.toDateString();
      var cls  = 'az-dp-day' + (sel?' selected':'') + (tod && !sel?' today':'');
      html += '<button class="' + cls + '" data-day="' + d + '">' + d + '</button>';
    }
    html += '</div>';

    pop.innerHTML = html;

    // Nav
    pop.querySelectorAll('.az-dp-nav').forEach(function(btn){
      btn.addEventListener('click', function(){
        var d = parseInt(this.getAttribute('data-d'));
        self.cur = new Date(yr, mo + d, 1);
        self.render();
      });
    });

    // Day select
    pop.querySelectorAll('.az-dp-day').forEach(function(btn){
      btn.addEventListener('click', function(){
        var day = parseInt(this.getAttribute('data-day'));
        self.sel = new Date(yr, mo, day);
        self.el.value = pad(day) + ' / ' + pad(mo+1) + ' / ' + yr;
        // Trigger change event so form validation picks it up
        self.el.dispatchEvent(new Event('change', { bubbles: true }));
        self.close();
      });
    });
  };

  // Auto-attach to all date inputs
  function initAll() {
    document.querySelectorAll('input[placeholder="DD / MM / YYYY"]').forEach(function(el){
      if (!el._dpAttached) new DatePicker(el);
    });
  }

  global.DatePicker   = DatePicker;
  global.initDatePickers = initAll;

  if (document.readyState === 'loading') {
    document.addEventListener('DOMContentLoaded', initAll);
  } else {
    initAll();
    // Also init on any dynamic content
    var obs = new MutationObserver(function(){
      document.querySelectorAll('input[placeholder="DD / MM / YYYY"]:not([_dpAttached])').forEach(function(el){
        new DatePicker(el);
      });
    });
    obs.observe(document.body, { childList: true, subtree: true });
  }

})(window);
